// src/pages/Internship.jsx
import React, { useEffect, useState } from 'react';

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({
    title: '',
    company: '',
    description: '',
  });
  const [editingIndex, setEditingIndex] = useState(null);

  const currentUser = JSON.parse(localStorage.getItem("currentUser"));
  const role = currentUser?.role;

  // Load internships from localStorage on mount
  useEffect(() => {
    const storedInternships = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(storedInternships);
  }, []);

  // Save internships to localStorage on change
  useEffect(() => {
    localStorage.setItem("internships", JSON.stringify(internships));
  }, [internships]);

  const handleInputChange = (e) => {
    setNewInternship({
      ...newInternship,
      [e.target.name]: e.target.value,
    });
  };

  const handleAdd = () => {
    if (!newInternship.title || !newInternship.company || !newInternship.description) return;
    setInternships([...internships, newInternship]);
    setNewInternship({ title: '', company: '', description: '' });
  };

  const handleEdit = (index) => {
    setNewInternship(internships[index]);
    setEditingIndex(index);
  };

  const handleUpdate = () => {
    const updated = [...internships];
    updated[editingIndex] = newInternship;
    setInternships(updated);
    setNewInternship({ title: '', company: '', description: '' });
    setEditingIndex(null);
  };

  const handleDelete = (index) => {
    const filtered = internships.filter((_, i) => i !== index);
    setInternships(filtered);
  };

  return (
    <div className="p-4 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold mb-4 text-center">Internship Management</h2>

      {(role === 'admin' || role === 'hr') && (
        <div className="mb-6 p-4 bg-gray-100 rounded">
          <h3 className="text-lg font-semibold mb-2">{editingIndex !== null ? 'Edit Internship' : 'Add Internship'}</h3>
          <input
            type="text"
            name="title"
            placeholder="Internship Title"
            value={newInternship.title}
            onChange={handleInputChange}
            className="border p-2 mr-2 mb-2 w-full"
          />
          <input
            type="text"
            name="company"
            placeholder="Company Name"
            value={newInternship.company}
            onChange={handleInputChange}
            className="border p-2 mr-2 mb-2 w-full"
          />
          <textarea
            name="description"
            placeholder="Description"
            value={newInternship.description}
            onChange={handleInputChange}
            className="border p-2 mb-2 w-full"
          />
          {editingIndex !== null ? (
            <button onClick={handleUpdate} className="bg-blue-500 text-white px-4 py-2 rounded mr-2">Update</button>
          ) : (
            <button onClick={handleAdd} className="bg-green-500 text-white px-4 py-2 rounded">Add</button>
          )}
        </div>
      )}

      <div>
        {internships.length === 0 ? (
          <p className="text-center">No internships available.</p>
        ) : (
          internships.map((item, index) => (
            <div key={index} className="border p-4 rounded mb-3 shadow">
              <h4 className="text-xl font-bold">{item.title}</h4>
              <p className="text-gray-600">Company: {item.company}</p>
              <p className="text-sm mt-1">{item.description}</p>
              {role === 'admin' && (
                <div className="mt-2">
                  <button onClick={() => handleEdit(index)} className="text-blue-500 mr-4">Edit</button>
                  <button onClick={() => handleDelete(index)} className="text-red-500">Delete</button>
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
